def maximumCostSubstring(s: str, chars: str, vals: List[int]) -> int:
    n = len(s)
    max_cost = 0
    for i in range(n):
        for j in range(i, n):
            cost = 0
            for k in range(i, j):
                if s[k] in chars:
                    cost += vals[chars.index(s[k])]
                else:
                    cost += vals[j - i + 1]
            max_cost = max(max_cost, cost)
    return max_cost

